/**
 * Helper function to convert a point array [x, y, z] to a string key.
 * @param {number[]} p 
 * @returns {string}
 */
const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

/**
 * Helper function to compute the midpoint of two points using floor division.
 * @param {number[]} p1 
 * @param {number[]} p2 
 * @returns {number[]} The resulting midpoint point [x, y, z].
 */
const computeMidpoint = (p1, p2) => {
    const x = Math.floor((p1[0] + p2[0]) / 2);
    const y = Math.floor((p1[1] + p2[1]) / 2);
    const z = Math.floor((p1[2] + p2[2]) / 2);
    return [x, y, z];
};

function solve(points, target) {
    const targetKey = pointToKey(target);

    // 1. Initialization and k=0 check
    let S_keys = new Set();
    let initialPoints = [];

    // Check k=0 and build S_0
    for (const p of points) {
        const pKey = pointToKey(p);
        S_keys.add(pKey);
        initialPoints.push(p);

        if (pKey === targetKey) {
            return 0;
        }
    }

    // If there are less than 2 unique points, no further generation is possible.
    if (points.length < 2) {
        return -1;
    }

    // S_prev_points holds the array representation of all unique points known so far (S_{k-1})
    let S_prev_points = initialPoints;

    let k = 0;

    while (true) {
        k++;
        let new_points_keys = new Set();
        let new_points_array = [];

        const currentPoints = S_prev_points;
        const N = currentPoints.length;

        // Generate new points (N_k) by pairing all distinct points in S_prev_points
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = currentPoints[i];
                const p2 = currentPoints[j];

                const c = computeMidpoint(p1, p2);
                const cKey = pointToKey(c);

                // Only process points that are truly new (not in S_keys yet)
                if (!S_keys.has(cKey)) {
                    new_points_keys.add(cKey);
                    new_points_array.push(c);

                    // Check if the target was generated in generation k
                    if (cKey === targetKey) {
                        return k;
                    }
                }
            }
        }

        // If no new unique points were generated, the process stalls.
        if (new_points_keys.size === 0) {
            return -1;
        }

        // Update the set of known points S_keys
        for (const key of new_points_keys) {
            S_keys.add(key);
        }

        // Update the array of available points S_prev_points for the next iteration
        // Append the newly found unique points.
        S_prev_points.push(...new_points_array);
    }
}

