fun solve(points: Array<Array<Long>>, target: Array<Long>): Long {

    // Helper function to convert a point array [x, y, z] to a string key.
    fun pointToKey(p: Array<Long>): String {
        return "${p[0]},${p[1]},${p[2]}"
    }

    // Helper function to compute the midpoint of two points using floor division.
    fun computeMidpoint(p1: Array<Long>, p2: Array<Long>): Array<Long> {
        val x = ((p1[0] + p2[0]) / 2).toLong()
        val y = ((p1[1] + p2[1]) / 2).toLong()
        val z = ((p1[2] + p2[2]) / 2).toLong()
        // Since inputs are non-negative, standard division followed by implicit floor (or explicit floor if needed for negative numbers, but here we deal with non-negative sums) works for positive results.
        // For explicit floor behavior with Longs for positive results, standard integer division in Kotlin/Java is sufficient.
        return arrayOf(x, y, z)
    }

    val targetKey = pointToKey(target)

    // 1. Initialization and k=0 check
    val knownKeys = mutableSetOf<String>()
    val allPoints = mutableListOf<Array<Long>>()

    // Check k=0 and build S_0
    for (p in points) {
        val pKey = pointToKey(p)
        knownKeys.add(pKey)
        allPoints.add(p)

        if (pKey == targetKey) {
            return 0
        }
    }

    // If there are less than 2 unique points, no further generation is possible.
    if (allPoints.size < 2) {
        return -1
    }

    var k: Long = 0

    // Iteratively generate points
    while (true) {
        k++
        val newlyGeneratedKeys = mutableSetOf<String>()
        val newlyGeneratedPoints = mutableListOf<Array<Long>>()

        val currentPoints = allPoints
        val N = currentPoints.size

        // Generate new points by pairing all distinct points currently known
        for (i in 0 until N) {
            for (j in i + 1 until N) {
                val p1 = currentPoints[i]
                val p2 = currentPoints[j]

                val c = computeMidpoint(p1, p2)
                val cKey = pointToKey(c)

                // Only process points that are truly new (not in knownKeys yet)
                if (!knownKeys.contains(cKey)) {

                    // Check if the target was generated in generation k
                    if (cKey == targetKey) {
                        return k
                    }

                    newlyGeneratedKeys.add(cKey)
                    newlyGeneratedPoints.add(c)
                }
            }
        }

        // If no new unique points were generated, the process stalls.
        if (newlyGeneratedKeys.isEmpty()) {
            return -1
        }

        // Update the set of known points
        for (key in newlyGeneratedKeys) {
            knownKeys.add(key)
        }

        // Update the array of available points for the next iteration
        allPoints.addAll(newlyGeneratedPoints)
    }
}

